p.m:
\displaystyle{\begin{aligned}
   \frac{5}{8} + \frac{39}{40}
        \amp = \frac{25}{40} + \frac{39}{40} \\
        \amp = \frac{25 + 39}{40} \\
        \amp = \frac{64}{40} \amp  \hbox{We can reduce this by dividing 8 into both the numerator and the denominator.}\\
        \amp = \frac{8}{5}
\end{aligned}
    }
